public sealed class GetOperationalTemplateInstallationLogUseCase(IOperationalTemplateInstallationRepository repo, ILogger<GetOperationalTemplateInstallationLogUseCase> logger) { public async Task<Result<IReadOnlyList<OperationalTemplateInstallationLogResponse>>> ExecuteAsync(Guid tenantId, Guid id, CancellationToken ct) { try { return Result<IReadOnlyList<OperationalTemplateInstallationLogResponse>>.Success(await repo.GetLogsAsync(tenantId, id, ct)); } catch (Exception ex) { logger.LogError(ex, "Installation logs failed"); return Result<IReadOnlyList<OperationalTemplateInstallationLogResponse>>.Failure(ex.Message); } } }
